SELECT p.* FROM user_nickname_profile p WHERE p.status = 'ACTIVE' AND p.user_id IN
#{uid}
AND p.id = ( SELECT s.id FROM user_nickname_profile s WHERE s.user_id = p.user_id AND s.status = 'ACTIVE' ORDER BY s.is_default DESC, s.created_at ASC, s.id ASC LIMIT 1 )

SELECT COUNT(*)
  FROM user_nickname_profile
 WHERE nickname = #{nickname}

   AND id != #{excludeId}

mapper.update:
UPDATE user_nickname_profile
   SET nickname = #{nickname},
       avatar_file_id = #{avatarFileId},
       bio = #{bio}
 WHERE id = #{id}
   AND user_id = #{userId}

UPDATE user_nickname_profile
   SET status = 'HIDDEN'
 WHERE id = #{id}
   AND user_id = #{userId}
   AND status = 'ACTIVE'

UPDATE user_nickname_profile
   SET is_default = 1
 WHERE id = #{id}
   AND user_id = #{userId}
   AND status = 'ACTIVE'

